@import url("https://fonts.googleapis.com/css2?family=Roboto+Mono:ital,wght@0,100..700;1,100..700&display=swap");

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

a,
p {
  display: block;
  text-decoration: none;
  text-transform: uppercase;
  color: #000;
  font-family: "Roboto Mono";
  font-size: 12px;
  font-weight: 400;
}

nav,
footer {
  position: absolute;
  left: 0;
  width: 100vw;
  padding: 1em;
  display: flex;
  justify-content: space-between;
  gap: 2em;
  z-index: 1;
}

nav {
  top: 0;
}

footer {
  bottom: 0;
}

.links,
.socials {
  display: flex;
  gap: 2em;
}

nav > *,
.links a {
  flex: 1;
}

.gradient-bg {
  position: absolute;
  bottom: 0;
  width: 100vw;
  height: 100svh;
  background: rgb(204, 204, 204);
  background: linear-gradient(
    0deg,
    rgba(204, 204, 204, 1) 0%,
    rgba(255, 255, 255, 1) 100%
  );
  z-index: 0;
}

.container {
  position: relative;
  width: 100vw;
  height: 100svh;
  overflow: hidden;
  z-index: 2;
}

.project-title-container {
  position: fixed;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 50%;
  aspect-ratio: 16/9;
}

#project-link {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  text-decoration: none;
  color: #fff;
}

.project-title-mask {
  position: relative;
  width: 100%;
  height: 16px;
  clip-path: polygon(0 0, 100% 0, 100% 100%, 0% 100%);
  overflow: hidden;
}

#project-title {
  display: block;
  position: relative;
  transform: translateY(0px);
  color: #fff;
  text-align: center;
  text-transform: uppercase;
  font-family: "Roboto Mono";
  font-size: 13px;
  line-height: 1;
  transition: transform 0.5s ease-in-out;
}

